module top_module(
    Q      ,
    reset    ,
    RESET_B
);output reg [1:0] Q;
    input  reset;
    input  RESET_B;

    always @(posedge reset or negedge RESET_B) begin
        if (!RESET_B) begin
            Q <= 2'b00;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
